<template><div class="overview-grid"><section class="surface info"><div class="surface-header"><div><h3>Application information</h3><p>应用运行时与交付配置</p></div></div><dl><div><dt>Language</dt><dd>{{ application.language }}</dd></div><div><dt>Framework</dt><dd>{{ application.framework }}</dd></div><div><dt>Build type</dt><dd>{{ application.build_type }}</dd></div><div><dt>Service port</dt><dd>{{ application.port }}</dd></div><div><dt>Namespace</dt><dd>{{ application.namespace }}</dd></div><div><dt>Branch</dt><dd>{{ application.branch }}</dd></div></dl></section><section class="surface"><div class="surface-header"><div><h3>Application Spec</h3><p>平台生成的声明式应用定义</p></div><el-button link type="primary" @click="copy">复制</el-button></div><pre>{{ spec }}</pre></section></div></template>
<script setup lang="ts">import yaml from'js-yaml';import{computed}from'vue';import{ElMessage}from'element-plus';import type{Application}from'../../types';const p=defineProps<{application:Application}>();const spec=computed(()=>yaml.dump(p.application.application_spec));function copy(){navigator.clipboard.writeText(spec.value);ElMessage.success('Application Spec 已复制')}

</script>
<style scoped>.overview-grid{display:grid;grid-template-columns:.85fr 1.15fr;gap:14px}.surface{overflow:hidden}.info dl{display:grid;grid-template-columns:1fr 1fr;margin:0;padding:8px 18px 19px}.info dl div{padding:12px 0;border-bottom:1px solid var(--border-soft)}dt{color:var(--muted);font-size:12px;margin-bottom:5px}dd{margin:0;font-size:12px;color:var(--text-2)}pre{height:285px;overflow:auto;margin:0;padding:17px;background:#101620;color:#c0cad8;font:12px/1.7 "SFMono-Regular",Consolas,monospace}@media(max-width:1000px){.overview-grid{grid-template-columns:1fr}}</style>
